//! The runtime guard path — monster-swarm does admission + bookkeeping, but
//! the actual sandbox + lease + revoke enforcement is monster-guard's job.
//! This module shells out to the `monster-guard` binary (loose coupling, the
//! same pattern monster-resident uses for plugin shims).

use std::fs::File;
use std::path::{Path, PathBuf};
use std::process::{Command, Stdio};

/// Locate the `monster-guard` binary: `$MONSTER_GUARD_BIN`, then the sibling
/// crate's build outputs, then PATH.
pub fn guard_bin() -> PathBuf {
    if let Ok(p) = std::env::var("MONSTER_GUARD_BIN") {
        return PathBuf::from(p);
    }
    if let Ok(dir) = std::env::var("CARGO_MANIFEST_DIR") {
        let base = PathBuf::from(dir);
        for rel in [
            "../monster-guard/target/release/monster-guard",
            "../monster-guard/target/debug/monster-guard",
        ] {
            let p = base.join(rel);
            if p.exists() {
                return p;
            }
        }
    }
    PathBuf::from("monster-guard")
}

/// The allowlisted directories a subagent node may be launched from. Secure by
/// default: if none are configured, no node resolves. Configure with
/// `$MONSTER_SWARM_NODES` (colon-separated) and/or `$DI_BIN_DIR`; the
/// distributed-inference build outputs are added when building via cargo.
fn node_dirs() -> Vec<PathBuf> {
    let mut dirs: Vec<PathBuf> = Vec::new();
    if let Ok(d) = std::env::var("MONSTER_SWARM_NODES") {
        for p in d.split(':').filter(|s| !s.is_empty()) {
            dirs.push(PathBuf::from(p));
        }
    }
    if let Ok(d) = std::env::var("DI_BIN_DIR") {
        dirs.push(PathBuf::from(d));
    }
    if let Ok(d) = std::env::var("CARGO_MANIFEST_DIR") {
        let base = PathBuf::from(d);
        dirs.push(base.join("../distributed-inference/target/release"));
        dirs.push(base.join("../distributed-inference/target/debug"));
    }
    dirs
}

/// Resolve a node binary to an absolute, allowlisted path. SECURITY: a holder
/// of `agent/spawn` chooses *what* to launch, so this is the boundary against
/// arbitrary code execution — the resolved binary must canonicalize to inside
/// an allowlisted directory, whether named bare or given as a path.
pub fn resolve_node(name: &str) -> Result<PathBuf, String> {
    if name.is_empty() || name.contains("..") {
        return Err(format!("invalid node '{name}'"));
    }
    let allowed: Vec<PathBuf> = node_dirs()
        .iter()
        .filter_map(|d| std::fs::canonicalize(d).ok())
        .collect();
    if allowed.is_empty() {
        return Err(
            "no node allowlist configured (set MONSTER_SWARM_NODES or DI_BIN_DIR)".to_string(),
        );
    }

    let candidate: PathBuf = if name.contains('/') {
        std::fs::canonicalize(name).map_err(|_| format!("node '{name}' not found"))?
    } else {
        let mut found: Option<PathBuf> = None;
        for d in &allowed {
            let p = d.join(name);
            if p.is_file() {
                found = Some(std::fs::canonicalize(&p).map_err(|e| e.to_string())?);
                break;
            }
        }
        found.ok_or_else(|| format!("node '{name}' not in the allowlisted node directories"))?
    };

    if !allowed.iter().any(|d| candidate.starts_with(d)) {
        return Err(format!(
            "node '{}' is outside the allowlisted node directories",
            candidate.display()
        ));
    }
    if !candidate.is_file() {
        return Err(format!("node '{}' is not a file", candidate.display()));
    }
    Ok(candidate)
}

/// `monster-guard delegate <name> <caps> --ttl <ttl> [--qspec <file>] [--oath <file>]`
/// — mint the command grant. When `qspec` is `Some`, the path is appended as
/// `--qspec <file>` so monster-guard runs the declared quality probe and refuses
/// to mint the grant unless it passes (quality-gated admission). When `oath` is
/// `Some`, the path is appended as `--oath <file>` so monster-guard binds the
/// sworn conduct oath into the grant as a UCAN fct and denies admission if the
/// requested caps exceed the oath's `max_caps` (conduct-bounded admission). Both
/// `None` is today's behavior: admission on capability + lease alone.
pub fn delegate(
    name: &str,
    caps: &[String],
    ttl_secs: i64,
    qspec: Option<&str>,
    oath: Option<&str>,
) -> Result<(), String> {
    let caps_arg = if caps.is_empty() { "-".to_string() } else { caps.join(",") };
    let ttl_str = ttl_secs.to_string();
    let mut args: Vec<&str> = vec!["delegate", name, &caps_arg, "--ttl", &ttl_str];
    if let Some(spec) = qspec {
        args.push("--qspec");
        args.push(spec);
    }
    if let Some(o) = oath {
        args.push("--oath");
        args.push(o);
    }
    // Silence the guard's stdout: callers (incl. the MCP server) keep stdout as
    // a pure protocol channel. Errors still surface via stderr + exit code.
    let status = Command::new(guard_bin())
        .args(&args)
        .stdout(Stdio::null())
        .status()
        .map_err(|e| format!("could not run monster-guard delegate: {e}"))?;
    if status.success() {
        Ok(())
    } else {
        Err(format!("monster-guard delegate failed (exit {:?})", status.code()))
    }
}

/// Launch `monster-guard run ... -- <node> <args>` as a detached, supervised
/// child (the lease auto-renews; revocation kills it). Returns the supervisor
/// pid. Node stdout/stderr go to `log` (or nowhere); `env` carries the
/// subagent's identity (id, did, keyfile path). The child outlives this CLI.
pub fn run_detached(
    name: &str,
    caps: &[String],
    lease_secs: u64,
    max_secs: Option<u64>,
    node: &Path,
    node_args: &[String],
    log: Option<&Path>,
    env: &[(String, String)],
) -> Result<u32, String> {
    let caps_arg = if caps.is_empty() { "-".to_string() } else { caps.join(",") };
    let mut cmd = Command::new(guard_bin());
    cmd.arg("run")
        .args(["--name", name, "--caps", &caps_arg, "--lease", &lease_secs.to_string()]);
    if let Some(m) = max_secs {
        cmd.args(["--max", &m.to_string()]);
    }
    cmd.arg("--").arg(node).args(node_args);

    for (k, v) in env {
        cmd.env(k, v);
    }

    // Detach and keep the parent's stdio clean (critical when the parent is the
    // MCP server): no stdin; node output to its log file, or nowhere.
    cmd.stdin(Stdio::null());
    match log {
        Some(path) => {
            let f = File::options()
                .create(true)
                .append(true)
                .open(path)
                .map_err(|e| format!("could not open node log {}: {e}", path.display()))?;
            let f2 = f.try_clone().map_err(|e| e.to_string())?;
            cmd.stdout(Stdio::from(f)).stderr(Stdio::from(f2));
        }
        None => {
            cmd.stdout(Stdio::null()).stderr(Stdio::null());
        }
    }

    let child = cmd
        .spawn()
        .map_err(|e| format!("could not launch monster-guard run for '{name}': {e}"))?;
    Ok(child.id())
}

/// `monster-guard revoke command <name>` — running invocation dies at the next
/// lease tick; future runs are denied.
pub fn revoke_command(name: &str) -> Result<(), String> {
    let status = Command::new(guard_bin())
        .args(["revoke", "command", name])
        .stdout(Stdio::null())
        .status()
        .map_err(|e| format!("could not run monster-guard revoke: {e}"))?;
    if status.success() {
        Ok(())
    } else {
        Err(format!("monster-guard revoke failed (exit {:?})", status.code()))
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // One test: mutating process env from parallel tests races, so keep the
    // node-allowlist checks sequential in a single function.
    #[test]
    fn resolve_node_allowlist_boundary() {
        std::env::set_var("MONSTER_SWARM_NODES", "/bin");
        std::env::remove_var("DI_BIN_DIR");
        std::env::remove_var("CARGO_MANIFEST_DIR");

        // Traversal is rejected outright.
        assert!(resolve_node("../etc/passwd").is_err());
        assert!(resolve_node("a/../../b").is_err());

        // A path that canonicalizes outside the allowlist is rejected — this is
        // the boundary against arbitrary code execution.
        assert!(
            resolve_node("/usr/bin/true").is_err(),
            "path outside allowlist must be rejected"
        );

        // An allowlisted bare name resolves (sh is in /bin on macOS + Linux).
        let p = resolve_node("sh").expect("sh should resolve in /bin");
        assert!(p.ends_with("sh"));
    }
}
